import {
  AfterViewChecked,
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  ElementRef,
  Input,
  OnChanges,
  OnDestroy,
  SimpleChanges,
  ViewChild,
} from '@angular/core';
import { ImageUrlPipe } from '@hau/shared/pipes/image-url.pipe';
import { IonIcon } from '@ionic/angular/standalone';
import { addIcons } from 'ionicons';
import { chevronBack, chevronForward, closeOutline, expandOutline } from 'ionicons/icons';
import Swiper from 'swiper';
import { FreeMode, Navigation, Pagination, Thumbs } from 'swiper/modules';

export interface PhotoItem {
  url: string;
  isDefault?: boolean;
}

@Component({
  selector: 'app-photo-carousel',
  templateUrl: './photo-carousel.component.html',
  styleUrls: ['./photo-carousel.component.scss'],
  standalone: true,
  imports: [ImageUrlPipe, IonIcon],
})
export class PhotoCarouselComponent implements AfterViewInit, AfterViewChecked, OnChanges, OnDestroy {
  @Input() photos: PhotoItem[] = [];
  @Input() altText = 'Photo';

  @ViewChild('mainSwiperEl') mainSwiperElRef?: ElementRef<HTMLElement>;
  @ViewChild('thumbSwiperEl') thumbSwiperElRef?: ElementRef<HTMLElement>;
  @ViewChild('lightboxSwiperEl') lightboxSwiperElRef?: ElementRef<HTMLElement>;

  lightboxOpen = false;

  private _mainInitialized = false;
  private _mainSwiper?: Swiper;
  private _thumbSwiper?: Swiper;
  private _lightboxSwiper?: Swiper;

  get hasPhotos(): boolean { return this.photos.length > 0; }
  get hasMultiple(): boolean { return this.photos.length > 1; }

  constructor(private readonly _cdr: ChangeDetectorRef) {
    addIcons({ chevronBack, chevronForward, closeOutline, expandOutline });
  }

  ngAfterViewInit(): void {
    // rAF ensures Ionic page-enter animation has painted at least once
    // so the container has its real offsetWidth before Swiper reads it
    requestAnimationFrame(() => {
      if (this._tryInitMainSwiper()) this._mainInitialized = true;
    });
  }

  // Catches the case where @if (hasMultiple) renders AFTER ngAfterViewInit
  // (e.g. photos arriving asynchronously). Runs once when the element appears.
  ngAfterViewChecked(): void {
    if (!this._mainInitialized && this.mainSwiperElRef && this.hasMultiple) {
      this._mainInitialized = true;
      requestAnimationFrame(() => this._tryInitMainSwiper());
    }
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['photos'] && !changes['photos'].firstChange) {
      this._destroyMain();
      this._mainInitialized = false;
    }
  }

  ngOnDestroy(): void {
    this._destroyMain();
    this._destroyLightbox();
  }

  openLightbox(index: number): void {
    this.lightboxOpen = true;
    document.body.style.overflow = 'hidden';
    // detectChanges() synchronously renders @if (lightboxOpen),
    // so lightboxSwiperElRef is populated before we call init
    this._cdr.detectChanges();
    this._initLightboxSwiper(index);
  }

  closeLightbox(): void {
    this.lightboxOpen = false;
    document.body.style.overflow = '';
    this._destroyLightbox();
  }

  private _tryInitMainSwiper(): boolean {
    if (!this.mainSwiperElRef || !this.hasMultiple) return false;
    this._initMainSwiper();
    return true;
  }

  private _initMainSwiper(): void {
    if (!this.mainSwiperElRef) return;
    const mainEl = this.mainSwiperElRef.nativeElement;

    if (this.thumbSwiperElRef) {
      this._thumbSwiper = new Swiper(this.thumbSwiperElRef.nativeElement, {
        modules: [FreeMode],
        slidesPerView: 'auto',
        spaceBetween: 8,
        watchSlidesProgress: true,
        freeMode: true,
      });
    }

    this._mainSwiper = new Swiper(mainEl, {
      modules: [Navigation, Pagination, ...(this._thumbSwiper ? [Thumbs] : [])],
      navigation: {
        prevEl: mainEl.querySelector<HTMLElement>('.pc-prev'),
        nextEl: mainEl.querySelector<HTMLElement>('.pc-next'),
      },
      pagination: {
        el: mainEl.querySelector<HTMLElement>('.pc-pagination'),
        clickable: true,
        dynamicBullets: true,
      },
      ...(this._thumbSwiper ? { thumbs: { swiper: this._thumbSwiper } } : {}),
      grabCursor: true,
    });
  }

  private _initLightboxSwiper(index: number): void {
    if (!this.lightboxSwiperElRef) return;
    const el = this.lightboxSwiperElRef.nativeElement;

    this._lightboxSwiper = new Swiper(el, {
      modules: [Navigation],
      initialSlide: index,
      navigation: {
        prevEl: el.querySelector<HTMLElement>('.pc-lb-prev'),
        nextEl: el.querySelector<HTMLElement>('.pc-lb-next'),
      },
      grabCursor: true,
      centeredSlides: true,
    });
  }

  private _destroyMain(): void {
    this._thumbSwiper?.destroy(true, true);
    this._mainSwiper?.destroy(true, true);
    this._thumbSwiper = undefined;
    this._mainSwiper = undefined;
    this._mainInitialized = false;
  }

  private _destroyLightbox(): void {
    this._lightboxSwiper?.destroy(true, true);
    this._lightboxSwiper = undefined;
  }
}
